//go:embed static
var staticFiles embed.FS

const maxUploadSize = 10 * 1024 * 1024 // 10 MB

// ── WebSocket envelope types ────────────────────────────────────────────────

type initEnv struct {
	Type       string          `json:"type"` // "init"
	SelfID     string          `json:"self_id"`
	Workspace  string          `json:"workspace"`
