  if (peers.length === 0) {
    onlineList.innerHTML = '<div class="online-empty">No peers yet</div>';
    return;
  }
  onlineList.innerHTML = peers.map(id =>
    `<div class="online-user"><span class="online-dot"></span>${escHtml(id)}</div>`
  ).join('');
}

